-- ============================================================
-- PAIO - Script de Traducciones al Español
-- OpenEMR 8.0.0.1
-- Diseño: tabla temporal + procedimiento de aplicación
-- Seguro, repetible, sin duplicados ni traducciones fantasmas
-- ============================================================
-- 
-- USO:
--   1. Editar la sección "DATOS" con las traducciones deseadas
--   2. Ejecutar el script completo: ddev mysql openemr < paio_translations.sql
--   3. Puede ejecutarse múltiples veces sin efectos secundarios
--
-- ============================================================

USE openemr;

--- Create backups
--CREATE TABLE lang_definitions_bak_20260401b SELECT * FROM lang_definitions;
--CREATE TABLE lang_constants_bak_20260401b SELECT * FROM lang_constants;

-- ============================================================
-- PASO 1: Crear tabla temporal de traducciones
-- ============================================================
DROP TEMPORARY TABLE IF EXISTS paio_translations_temp;

CREATE TEMPORARY TABLE paio_translations_temp (
    constant_name VARCHAR(255) NOT NULL,
    def_latam     MEDIUMTEXT,   -- Spanish Latin American (lang_id=4)
    def_spain     MEDIUMTEXT    -- Spanish Spain (lang_id=3)
);

-- ============================================================
-- PASO 2: DATOS — Editar esta sección con las traducciones
-- Formato: (constant_name, traduccion_latin_america, traduccion_españa)
-- Si latam = spain usar el mismo valor en ambas columnas
-- ============================================================

INSERT INTO paio_translations_temp (constant_name, def_latam, def_spain) VALUES

-- ('Pecularities in many browsers may mean that the output below enters your screen in sudden jerks and that there are long pauses of several seconds where it  appears as though things may have crashed. That is not the case, you will eventually see output coming out line by line. There may be sequential numbers appearing  below, this is to indicate that even though nothing else may be displaying there is activity going on. These numbers will be interspersed with the content of the  billing and that is normal.', 'Peculiaridades en varios exploradores pueden causar que la información abajo aparece bruscamente, y ocurren pausas extensas que aparentan que el sistema se ha dañado. Este no es el caso, y eventualmente verá información desplegada línea por línea. Podrían aparecer números secuenciales para indicar que aunque no aparezca nada más, el sistema tiene actividad. Estos números serán entremezclados con el contenido de la facturación, y es normal.', 'Peculiaridades en varios programas de exploración pueden asumir que la información abajo aparece bruscamente, y ocurren pausas extensas que aparentan que el sistema se ha dañado. Este no es el caso, y eventualmente verá información desplegada línea por línea. Podrían aparecer números secuenciales para indicar que aunque no aparezca nada más, el sistema tiene actividad. Estos números serán entremezclados con el contenido de la facturación, y es normal.'),
