-- 3a. Insertar constantes que no existen (comparando con TRIM)
INSERT INTO lang_constants (constant_name)
    SELECT TRIM(t.constant_name)
    FROM paio_translations_temp t
    WHERE NOT EXISTS (
        SELECT 1 FROM lang_constants lc
        WHERE TRIM(lc.constant_name) = TRIM(t.constant_name)
    );

-- 3b. Actualizar definiciones existentes en Latin American (lang_id=4)
UPDATE lang_definitions ld
JOIN lang_constants lc ON ld.cons_id = lc.cons_id
JOIN paio_translations_temp t ON TRIM(lc.constant_name) = TRIM(t.constant_name)
SET ld.definition = t.def_latam
WHERE ld.lang_id = 4
AND lc.cons_id = (
    SELECT MIN(cons_id) FROM lang_constants
    WHERE TRIM(constant_name) = TRIM(t.constant_name)
);

-- 3c. Insertar definiciones Latin American que no existen (lang_id=4)
INSERT INTO lang_definitions (cons_id, lang_id, definition)
    SELECT 
        (SELECT MIN(cons_id) FROM lang_constants WHERE TRIM(constant_name) = TRIM(t.constant_name)),
        4,
        t.def_latam
    FROM paio_translations_temp t
    WHERE NOT EXISTS (
        SELECT 1 FROM lang_definitions ld
        JOIN lang_constants lc ON ld.cons_id = lc.cons_id
        WHERE TRIM(lc.constant_name) = TRIM(t.constant_name)
        AND ld.lang_id = 4
        AND lc.cons_id = (SELECT MIN(cons_id) FROM lang_constants WHERE TRIM(constant_name) = TRIM(t.constant_name))
    );

-- 3d. Actualizar definiciones existentes en Spain (lang_id=3)
UPDATE lang_definitions ld
JOIN lang_constants lc ON ld.cons_id = lc.cons_id
JOIN paio_translations_temp t ON TRIM(lc.constant_name) = TRIM(t.constant_name)
SET ld.definition = t.def_spain
WHERE ld.lang_id = 3
AND lc.cons_id = (
    SELECT MIN(cons_id) FROM lang_constants
    WHERE TRIM(constant_name) = TRIM(t.constant_name)
);

-- 3e. Insertar definiciones Spain que no existen (lang_id=3)
INSERT INTO lang_definitions (cons_id, lang_id, definition)
    SELECT 
        (SELECT MIN(cons_id) FROM lang_constants WHERE TRIM(constant_name) = TRIM(t.constant_name)),
        3,
        t.def_spain
    FROM paio_translations_temp t
    WHERE NOT EXISTS (
        SELECT 1 FROM lang_definitions ld
        JOIN lang_constants lc ON ld.cons_id = lc.cons_id
        WHERE TRIM(lc.constant_name) = TRIM(t.constant_name)
        AND ld.lang_id = 3
        AND lc.cons_id = (SELECT MIN(cons_id) FROM lang_constants WHERE TRIM(constant_name) = TRIM(t.constant_name))
    );

-- ============================================================
-- PASO 4: Verificación final
-- ============================================================
SELECT 
    t.constant_name,
    ld4.definition AS latam,
    ld3.definition AS spain,
    CASE 
        WHEN ld4.definition IS NULL AND ld3.definition IS NULL THEN '❌ SIN TRADUCCION'
        WHEN ld4.definition IS NULL THEN '⚠ FALTA LATAM'
        WHEN ld3.definition IS NULL THEN '⚠ FALTA SPAIN'
        ELSE '✓ OK'
    END AS estado
FROM paio_translations_temp t
LEFT JOIN lang_constants lc ON TRIM(lc.constant_name) = TRIM(t.constant_name)
    AND lc.cons_id = (SELECT MIN(cons_id) FROM lang_constants WHERE TRIM(constant_name) = TRIM(t.constant_name))
LEFT JOIN lang_definitions ld4 ON lc.cons_id = ld4.cons_id AND ld4.lang_id = 4
LEFT JOIN lang_definitions ld3 ON lc.cons_id = ld3.cons_id AND ld3.lang_id = 3
ORDER BY estado DESC, t.constant_name;

-- ============================================================
-- PASO 5: Limpiar tabla temporal
-- ============================================================
DROP TEMPORARY TABLE IF EXISTS paio_translations_temp;